compliant:
#include <stdlib.h>
struct s {
    uint16_t len;
    uint32_t *data; // Compliant - use pointer instead
};

struct s *create_s(uint16_t len) {
    struct s *s1 = malloc(sizeof(struct s));
    s1->len = len;
    s1->data = malloc(len * sizeof(uint32_t));
    return s1;
}

#define MAX_BUFFER_SIZE 256
struct buffer {
    size_t size;
    char data[MAX_BUFFER_SIZE]; // Compliant - fixed-size array
};
